#include <stdio.h>
#include <math.h>

int lint(int n) {
    int h = n;
    int i = 0;
    while (h > 0) {
        h = h / 10;
        i++;
    }
    return i;
}

int main() {
    int k;
    scanf("%d", &k);
    int list[1000] = {1};
    int n = 1;
    int y = 1;
    for (; y < k;) {
        n = n + 1;
        int p = lint(n);
        for (int i = p; i > 0; i--) {
            int e = pow(10, i - 1);
            int x = n / e;
            int z = x % 10;
            list[y++] = z;
        }
    }
    printf("%d", list[k - 1]);
    return 0;
}
```

